mapper.delete:
DELETE  FROM OMS.ITEM_WISHLIST
 WHERE  USER_LOGIN_NO = #{userLoginNo}
   AND  ITEM_NO = #{itemNo}

mapper.select:
SELECT  COUNT(*) > 0
  FROM  OMS.ITEM_WISHLIST
 WHERE  USER_LOGIN_NO = #{userLoginNo}
   AND  ITEM_NO = #{itemNo}


INSERT  INTO OMS.ITEM_WISHLIST (
        USER_LOGIN_NO
     ,  ITEM_NO
     ,  CREATED_DT
)
VALUES  (
        #{userLoginNo}
     ,  #{itemNo}
     ,  #{createdDt}
)



SELECT  COUNT(*) > 0
  FROM  OMS.ITEM_WISHLIST iw
 WHERE  iw.USER_LOGIN_NO = #{userLoginNo}
   AND  iw.ITEM_NO = #{itemNo}



SELECT  ul.USER_LOGIN_NO AS userLoginNo
     ,  item.ITEM_NO AS itemNo
     ,  item.ITEM_NAME AS itemName
     ,  iw.CREATED_DT AS createdDt
  FROM  OMS.ITEM_WISHLIST iw
  JOIN  OMS.USER_LOGIN ul ON ul.USER_LOGIN_NO = iw.USER_LOGIN_NO
  JOIN  OMS.ITEM item ON item.ITEM_NO = iw.ITEM_NO
 WHERE  iw.USER_LOGIN_NO = #{userLoginNo}
   AND  item.DELETED_DT IS NULL
 ORDER BY iw.CREATED_DT DESC
